        int sum = 0;
        for (int num : nums) sum += num;
        if (sum % k) return false;
        int target = sum / k;
        vector<bool> visited(nums.size(), false);
        return dfs(nums, k, target, 0, visited);
    }
    bool dfs(vector<int>& nums, int k, int target, int start, vector<bool>& visited) {
        if (k == 1) return true;
        for (int i = start; i < nums.size(); i++) {
            if (!visited[i] && nums[i] <= target) {
                visited[i] = true;
                if (dfs(nums, k - 1, target, 0, visited)) return true;
                visited[i] = false;
            }
        }
        return false;
    }
};
